import React from 'react';
import { Navbar, Nav, Container, NavLink } from 'react-bootstrap';

const Header = () => {
  return (
    <Navbar bg="dark" variant="dark" expand="lg">
      <Container>
        <Navbar.Toggle aria-controls="basic-navbar-nav" />
        <Navbar.Collapse id="basic-navbar-nav">
          <Nav className="justify-content-end">
            <Nav.Link href="#" disabled>
              &copy; {new Date().getFullYear()} Your Name. All rights reserved.
            </Nav.Link>
          </Nav>
          <Nav className="ms-auto social-icons">
            <Nav.Link href="https://www.linkedin.com/in/your-profile" target="_blank">
              <FaLinkedin size={24} color="white" />
            </Nav.Link>
            <Nav.Link href="https://github.com/your-profile" target="_blank">
              <FaGithub size={24} color="white" />
            </Nav.Link>
            <Nav.Link href="https://twitter.com/your-profile" target="_blank">
              <FaTwitter size={24} color="white" />
            </Nav.Link>
          </Nav>
        </Navbar.Collapse>
      </Container>
    </Navbar>
  );
};

export default Header;
